function c(){return{formatPrice:(n,t="0.00")=>{if(n==null||n==="")return t;const e=Number(n);return isNaN(e)?t:e.toFixed(2)},formatDate:n=>{if(!n)return"-";const t=new Date(n);if(isNaN(t.getTime()))return"-";const e=t.getFullYear(),r=String(t.getMonth()+1).padStart(2,"0"),a=String(t.getDate()).padStart(2,"0"),o=String(t.getHours()).padStart(2,"0"),i=String(t.getMinutes()).padStart(2,"0"),s=String(t.getSeconds()).padStart(2,"0");return`${e}-${r}-${a} ${o}:${i}:${s}`},formatRemainingTime:n=>{if(!n)return null;const t=new Date(n).getTime(),e=new Date().getTime(),r=t-e;if(r<=0)return"已过期";const a=Math.floor(r/(1e3*60*60*24)),o=Math.floor(r%(1e3*60*60*24)/(1e3*60*60)),i=Math.floor(r%(1e3*60*60)/(1e3*60));return a>0?`${a}天 ${o}小时`:o>0?`${o}小时 ${i}分`:`${i}分钟`}}}export{c as u};
